What is the output of the following program?
#include <stdio.h>
void main ()
{
int a=40;
float b;
b=++a;
printf("%d, %f", a, ++b);
}

What is the output of the following program?
#include <stdio.h>
void main ()
{
int a=-7;
float b;
b=a++;
printf("%d, %f", a, ++b);
}

What is the output of the following program?
#include <stdio.h>
void main ()
{
int i=-1;
printf("sizeof(i) = %d", sizeof(i));
}

What is the output of the following program?
#include <stdio.h>
void main()
{
int x=-1, y=1, z=0;
if(x && y++ && z)
++x, y++, --z;
printf("%d, %d, %d", x++, y++, z++);
}

What is the output of the following program?
#include <stdio.h>
enum colors {RED, BROWN, ORANGE};
void main()
{
printf ("%d..%f..%d", RED, BROWN, ORANGE);
}

