What is the output of the following program?
#include <stdio.h>
void main()
{
int i=-9;
printf("%d %d %d", i++, ++i, ++i);
}

What is the output of the following program?
#include<stdio.h>
void main()
{
int **ptr;
int temp = 65;
ptr[0] = &temp;
printf("%d", ptr[0][0]);
}

What is the output of the following program?
#include <stdio.h>
#include <stdlib.h>
void main()
{
int *ptr;
ptr[2]=30;
ptr=(int*) calloc(3, sizeof(int));
printf("%d", *ptr);
free(ptr);
}

What is the output of the following program?
#include <iostream>
using namespace std;
int addition (int a, int b)
{
return a+b;
}
double addition (double a, double b)
{
return a+b;
}
int main ()
{
cout<< addition (35,20) << ";";
cout<< addition (34.1,12.7);
return 0;
}

What is the output of the following program?
#include <iostream>
using namespace std;
template <class C1, class C2>
bool is_equal (C1 var1, C2 var2)
{
return (var1==var2);
}
int main ()
{
if (is_equal(10,10.0))
cout<< "Equal";
else
cout<< "Not equal";
return 0;
}

What is the output of the following program?
#include <iostream>
using namespace std;
int main()
{
int var = 0;
while (var<10)
{
cout<< var << " ";
var++;
}
cout<< var;
return 0;
}

What is the output of the following program?
#include <iostream>
using namespace std;
struct demo
{
int var;
};
int main()
{
demo str;
demo *ptr;
str.var = 100;
ptr = &str;
cout<<ptr->var;
return 0;
}

